const root = '/opt/homebrew/lib/node_modules/agent-browser';
function findFiles(dir, match, out=[]) {
  for (const ent of fs.readdirSync(dir, {withFileTypes:true})) {
    const p = path.join(dir, ent.name);
    if (ent.isDirectory()) {
      if (ent.name === 'node_modules') continue;
      findFiles(p, match, out);
    } else {
      if (match(p)) out.push(p);
    }
  }
  return out;
}
const jsFiles = findFiles(root, p=>p.endsWith('.js'));
let hit = [];
for (const f of jsFiles) {
  const txt = fs.readFileSync(f,'utf8');
  if (txt.includes('Browser not launched') || txt.includes('launch first')) hit.push(f);
}
